import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });
api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

const PatientPortal = () => {
    const [activeTab, setActiveTab] = useState('onboarding');
    const [history, setHistory] = useState([]);

    // Profile State
    const [profile, setProfile] = useState({ smoking: 'Never', sleep: '7', conditions: '' });
    const [savingProfile, setSavingProfile] = useState(false);

    // Tracker State
    const [trackerData, setTrackerData] = useState({ steps: 7240, heartRate: 72 });

    // Prevention Content
    const [preventionData, setPreventionData] = useState([]);
    const [loadingPrevention, setLoadingPrevention] = useState(false);

    // Chat state
    const [messages, setMessages] = useState([
        { role: 'ai', content: 'Hello! I am your AI Health Assistant. How can I help you today?' }
    ]);
    const [currentMessage, setCurrentMessage] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const chatEndRef = useRef(null);

    useEffect(() => {
        // Fetch Profile
        api.get('/patient/profile').then(res => {
             if (res.data.success && res.data.data.smoking) setProfile(res.data.data);
        }).catch(err => console.error(err));

        // Fetch History
        api.get('/history')
           .then(res => setHistory(res.data.data || []))
           .catch(err => console.error("Error fetching patient history", err));

        // Fetch Prevention content safely
        setLoadingPrevention(true);
        api.get('/patient/prevention')
           .then(res => setPreventionData(res.data.data || []))
           .finally(() => setLoadingPrevention(false));
    }, []);

    // Tracker Simulation
    useEffect(() => {
        if (activeTab === 'tracker') {
            const interval = setInterval(() => {
                setTrackerData(prev => ({
                    steps: prev.steps + Math.floor(Math.random() * 10),
                    heartRate: 65 + Math.floor(Math.random() * 20)
                }));
            }, 3000);
            return () => clearInterval(interval);
        }
    }, [activeTab]);

    useEffect(() => {
        if (chatEndRef.current) {
            chatEndRef.current.scrollIntoView({ behavior: "smooth" });
        }
    }, [messages]);

    const handleSaveProfile = async (e) => {
        e.preventDefault();
        setSavingProfile(true);
        try {
            await api.post('/patient/profile', profile);
            alert("Profile Saved!");
        } catch (e) {
            alert("Failed to save profile.");
        }
        setSavingProfile(false);
    };

    const handleSendMessage = async () => {
        if (!currentMessage.trim()) return;

        const userMsg = currentMessage;
        setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
        setCurrentMessage('');
        setIsTyping(true);

        try {
            const systemPrompt = "You are a helpful, empathetic medical AI assistant talking directly to a patient. Give short, compassionate responses.";
            const res = await api.post('/chat', { message: userMsg, systemPrompt });
            setMessages(prev => [...prev, { role: 'ai', content: res.data.response }]);
        } catch (error) {
            setMessages(prev => [...prev, { role: 'ai', content: 'Sorry, I am having trouble connecting to my service right now.' }]);
        } finally {
            setIsTyping(false);
        }
    };

    const chartData = history.slice().reverse().map(h => ({
        date: new Date(h.timestamp).toLocaleDateString(),
        riskConfidence: h.confidence
    }));

    return (
        <div className="portal-container slide-up">
            <div className="portal-sidebar">
                <h3 className="gradient-text" style={{ padding: '0 1rem', marginBottom: '1rem' }}>My Health</h3>
                <button className={`portal-sidebar-btn ${activeTab === 'onboarding' ? 'active' : ''}`} onClick={() => setActiveTab('onboarding')}>📝 Health Questionnaire</button>
                <button className={`portal-sidebar-btn ${activeTab === 'tracker' ? 'active' : ''}`} onClick={() => setActiveTab('tracker')}>⌚ Activity Tracker</button>
                <button className={`portal-sidebar-btn ${activeTab === 'timeline' ? 'active' : ''}`} onClick={() => setActiveTab('timeline')}>📈 Risk Trend & History</button>
                <button className={`portal-sidebar-btn ${activeTab === 'education' ? 'active' : ''}`} onClick={() => setActiveTab('education')}>📚 Prevention Hub</button>
                <button className={`portal-sidebar-btn ${activeTab === 'chat' ? 'active' : ''}`} onClick={() => setActiveTab('chat')}>💬 Secure Telehealth</button>
            </div>

            <div className="portal-content">
                {activeTab === 'onboarding' && (
                    <div className="portal-panel">
                        <h2>Onboarding & Health Questionnaire</h2>
                        <p className="subtitle">Help us understand your baseline health for better predictions.</p>
                        <form onSubmit={handleSaveProfile} style={{ display: 'flex', flexDirection: 'column', gap: '1rem', maxWidth: '600px' }}>
                            <div>
                                <label className="data-label">Do you smoke?</label>
                                <select value={profile.smoking} onChange={e => setProfile({...profile, smoking: e.target.value})} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '0.5rem', fontFamily: 'inherit' }}>
                                    <option>Never</option>
                                    <option>Occasionally</option>
                                    <option>Regularly</option>
                                </select>
                            </div>
                            <div>
                                <label className="data-label">Average hours of sleep per night</label>
                                <input type="number" value={profile.sleep} onChange={e => setProfile({...profile, sleep: e.target.value})} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '0.5rem' }} />
                            </div>
                            <div>
                                <label className="data-label">Any known chronic conditions? (comma separated)</label>
                                <input type="text" value={profile.conditions} onChange={e => setProfile({...profile, conditions: e.target.value})} placeholder="E.g., Asthma, Hypertension" style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '0.5rem' }} />
                            </div>
                            <button type="submit" className="btn-primary glow-btn" style={{marginTop: '1rem'}} disabled={savingProfile}>
                                {savingProfile ? 'Saving...' : 'Save Profile'}
                            </button>
                        </form>
                    </div>
                )}

                {activeTab === 'tracker' && (
                    <div className="portal-panel">
                        <h2>Device Integration & Activity Tracker</h2>
                        <p className="subtitle">Live sync with your smartwatch or wearable.</p>
                        <div className="feature-grid">
                            <div className="data-card" style={{alignItems: 'center', textAlign: 'center'}}>
                                <h3>Daily Steps</h3>
                                <div className="activity-ring-container" style={{ margin: '1rem 0', background: `conic-gradient(#3b82f6 ${(trackerData.steps/10000)*100}%, #e2e8f0 0)` }}>
                                    <div className="activity-ring-inner">
                                        <span className="ring-value">{trackerData.steps}</span>
                                        <span className="ring-label">of 10k</span>
                                    </div>
                                </div>
                            </div>
                            <div className="data-card" style={{alignItems: 'center', textAlign: 'center'}}>
                                <h3>Heart Rate</h3>
                                <div className="activity-ring-container" style={{ margin: '1rem 0', background: 'conic-gradient(#ef4444 85%, #e2e8f0 0)' }}>
                                    <div className="activity-ring-inner">
                                        <span className="ring-value pulse" style={{color: '#ef4444', transition: 'all 0.5s ease'}}>{trackerData.heartRate}</span>
                                        <span className="ring-label">BPM (Live)</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'timeline' && (
                    <div className="portal-panel">
                        <h2>Personalized Risk Trend Timeline</h2>
                        <p className="subtitle">Track how your lifestyle changes affect your AI predicted health risks.</p>

                        <div style={{ height: '300px', width: '100%', marginBottom: '2rem', background: '#f8fafc', padding: '1rem', borderRadius: '12px' }}>
                            {history.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={chartData}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="date" />
                                        <YAxis label={{ value: 'Risk Confidence %', angle: -90, position: 'insideLeft' }} />
                                        <Tooltip />
                                        <Line type="monotone" dataKey="riskConfidence" stroke="#667eea" strokeWidth={3} dot={{r: 6}} />
                                    </LineChart>
                                </ResponsiveContainer>
                            ) : (
                                <div style={{display:'flex', height:'100%', alignItems:'center', justifyContent:'center', color:'#718096'}}>No trend data available. Complete an assessment first.</div>
                            )}
                        </div>

                        <div>
                            <h3 style={{marginBottom: '1rem'}}>AI Analysis History</h3>
                            {history.length === 0 ? (
                                <p style={{color: '#718096'}}>No assessments taken yet.</p>
                            ) : (
                                history.map((item, idx) => (
                                    <div className="timeline-event" key={item._id || idx}>
                                        <div className="timeline-time">{new Date(item.timestamp).toLocaleDateString()}</div>
                                        <div className="timeline-desc">
                                            <strong>{item.predictedDisease}:</strong> Evaluated based on {item.symptoms.length} symptoms with {item.confidence.toFixed(1)}% confidence.
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'education' && (
                    <div className="portal-panel">
                        <h2>Educational Content & Prevention Hub</h2>
                        <p className="subtitle">Tailored content generated by AI based on your recent symptoms and profile.</p>

                        {loadingPrevention ? (
                            <p>Loading your personalized insights...</p>
                        ) : (
                            <div className="feature-grid">
                                {preventionData.map((article, idx) => (
                                    <div key={idx} className="data-card" style={{background: 'linear-gradient(135deg, #1e3a8a, #3b82f6)', color: 'white', minHeight: '150px', display:'flex', flexDirection:'column', justifyContent: 'space-between'}}>
                                        <h3 style={{color: 'white', fontSize:'1.2rem', marginBottom:'0.5rem'}}>{article.title}</h3>
                                        <p style={{color: '#e2e8f0', fontSize: '0.9rem'}}>{article.category} | {article.readTime}</p>
                                        <button className="btn-secondary" style={{marginTop:'auto', width:'fit-content', background:'rgba(255,255,255,0.2)', color:'white', border:'none'}}>Read More</button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'chat' && (
                    <div className="portal-panel">
                        <h2>Secure Chat & Telehealth</h2>
                        <p className="subtitle">Connect directly with your care team or the AI health assistant.</p>
                        <div className="chat-box" style={{ background: '#f8fafc', borderRadius: '12px', padding: '1rem', height: '400px', display: 'flex', flexDirection: 'column' }}>
                            <div className="chat-messages" style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '1rem', paddingBottom: '1rem' }}>
                                {messages.map((msg, idx) => (
                                    <div key={idx} style={{
                                        alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                                        background: msg.role === 'user' ? '#667eea' : '#e2e8f0',
                                        color: msg.role === 'user' ? 'white' : '#1a202c',
                                        padding: '0.8rem 1.2rem',
                                        borderRadius: '20px',
                                        maxWidth: '80%'
                                    }}>
                                        {msg.content}
                                    </div>
                                ))}
                                {isTyping && (
                                    <div style={{ alignSelf: 'flex-start', color: '#718096', fontStyle: 'italic', padding: '0.5rem' }}>
                                        AI is typing...
                                    </div>
                                )}
                                <div ref={chatEndRef} />
                            </div>
                            <div className="chat-input-area" style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem' }}>
                                <input 
                                    type="text" 
                                    className="chat-input" 
                                    placeholder="Type a secure message..." 
                                    style={{ flex: 1, padding: '0.8rem', borderRadius: '20px', border: '1px solid #cbd5e0' }}
                                    value={currentMessage}
                                    onChange={(e) => setCurrentMessage(e.target.value)}
                                    onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                                />
                                <button className="chat-send" style={{ background: '#667eea', color: 'white', border: 'none', padding: '0 1.5rem', borderRadius: '20px', cursor: 'pointer' }} onClick={handleSendMessage} disabled={isTyping}>
                                    Send
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PatientPortal;
